const input = $json;

const required = ['jobId', 'prompt', 'aspectRatio', 'durationSec'];
const missing = required.filter((k) => input[k] === undefined || input[k] === null || input[k] === '');
if (missing.length) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

const boundedRepair = {
  maxAttempts: Number(input.maxRepairAttempts ?? 2),
  allowPromptTrim: true,
  allowDurationClamp: true,
  maxDurationSec: 8,
  minDurationSec: 4
};

return [{
  json: {
    status: 'accepted',
    stage: 'intake_complete',
    payload: {
      jobId: String(input.jobId),
      prompt: String(input.prompt),
      aspectRatio: String(input.aspectRatio),
      durationSec: Number(input.durationSec),
      model: String(input.model ?? 'veo'),
      negativePrompt: String(input.negativePrompt ?? ''),
      metadata: input.metadata ?? {}
    },
    repair: boundedRepair,
    approval: {
      required: true,
      status: 'pending'
    },
    timestamps: {
      intakeAt: new Date().toISOString()
    }
  }
}];
